  ('dietitian-moex-03733', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '世界衛生組織（WHO）專家會議建議，使用鹽來做為添加下列何種營養素的載體（vehicle for fortification）， 以期達到降低心血管疾病及該營養素缺乏症的雙重效益？', '["鈣", "鉀", "鐵", "碘"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "a25566c0cb68", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03734', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '病例對照研究（Case-control study）方法的樣本中，若病例組有一位32歲患者，則對照組也需找一位 32±3歲的健康者，是採取那一種方式來控制干擾因子？', '["配對（Matching）", "分層（Stratification）", "隨機分派（Randomization）", "限制（Restriction）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "a25566c0cb68", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03735', 'dietitian', 'dietitian-moex-100-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某國小六年級全體同學360人，在95年9月開學時做視力檢查，有55人罹患近視；96年2月開學時增 加了15人，在計算95學年上學期近視發生率時，分母應帶入多少人數，亦即有危險總人數為何？', '["360", "345", "305", "290"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "a25566c0cb68", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03736', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試中醫師、營養師、心理師、 全一張 高等暨普通考試醫事人員考試暨高等考試醫師考試分試考試試題  （正面） 等    別 ：高等考試 類    科 ：營養師 科    目 ：團體膳食設計與管理 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "2c00818738db", "answer_pdf_sha1": "772022cd4142", "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 100, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-03737', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何者不是「非選擇性菜單」之特點？', '["份量易控制", "有較多之盤餘量", "考慮顧客之嗜好", "便於大量製備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "2c00818738db", "answer_pdf_sha1": "772022cd4142", "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
