  ('dietitian-moex-03739', 'dietitian', 'dietitian-moex-100-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '餐會中供應葷菜五道，每人可選擇二道，預估有60位同學用餐，則每道葷菜需平均設計多少人份？', '["24", "48", "80", "120"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:31:02+00:00", "source_pdf_sha1": "2c00818738db", "answer_pdf_sha1": "772022cd4142", "source_family": "moex-gov-tw", "moex": {"exam_code": "100030", "c": "108", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "100", "exam_name": "100年第一次專技中醫師、營養師、心理師、醫事人員暨醫師考試分試考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
